  1	import * as React from 'react';
  2	
  3	import { modelToGroupVersionKind, NodeModel } from '@kubevirt-ui/kubevirt-api/console';
  4	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
  5	import Loading from '@kubevirt-utils/components/Loading/Loading';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import { GreenCheckCircleIcon, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  Alert,
 10	  AlertVariant,
 11	  Button,
 12	  Flex,
 13	  FlexItem,
 14	  pluralize,
 15	  Popover,
 16	} from '@patternfly/react-core';
 17	
 18	type NodeCheckerAlertProps = {
 19	  nodesLoaded: boolean;
 20	  prefferedQualifiedNodes?: IoK8sApiCoreV1Node[];
 21	  qualifiedNodes: IoK8sApiCoreV1Node[];
 22	};
 23	
 24	const NodeCheckerAlert: React.FC<NodeCheckerAlertProps> = ({
 25	  nodesLoaded,
 26	  prefferedQualifiedNodes,
 27	  qualifiedNodes,
 28	}) => {
 29	  const { t } = useKubevirtTranslation();
 30	  if (!nodesLoaded) {
 31	    return <Loading />;
 32	  }
 33	
 34	  const qualifiedNodesSize = qualifiedNodes?.length || 0;
 35	  const prefferedQualifiedNodesSize = prefferedQualifiedNodes?.length ?? 0;
 36	
 37	  const prefferedQualifiedNodesNames = prefferedQualifiedNodes?.map((node) => node?.metadata?.name);
 38	
 39	  const matchingNodeText = pluralize(
 40	    qualifiedNodesSize ? qualifiedNodesSize : prefferedQualifiedNodesSize,
 41	    'Node',
 42	  );
 43	
 44	  let nodes = [];
 45	  if (qualifiedNodesSize) {
 46	    nodes = qualifiedNodes;
 47	  } else if (prefferedQualifiedNodesSize) {
 48	    nodes = prefferedQualifiedNodes;
 49	  }
 50	
 51	  return (
 52	    <Alert
 53	      title={
 54	        <>
 55	          {!!qualifiedNodesSize || !!prefferedQualifiedNodesSize ? (
 56	            <>
 57	              {t('{{matchingNodeText}} matching', {
 58	                matchingNodeText,
 59	              })}
 60	              {!!qualifiedNodesSize &&
 61	                !!prefferedQualifiedNodesSize &&
 62	                t(', {{prefferedQualifiedNodesSize}} matching preferred Nodes found', {
 63	                  prefferedQualifiedNodesSize:
 64	                    qualifiedNodesSize < prefferedQualifiedNodesSize
 65	                      ? qualifiedNodesSize
 66	                      : prefferedQualifiedNodesSize,
 67	                })}
 68	            </>
 69	          ) : (
 70	            t('No matching Nodes found for the labels')
 71	          )}
 72	        </>
 73	      }
 74	      variant={
 75	        qualifiedNodesSize || prefferedQualifiedNodesSize
 76	          ? AlertVariant.success
 77	          : AlertVariant.warning
 78	      }
 79	      isInline
 80	    >
 81	      {qualifiedNodesSize || prefferedQualifiedNodesSize ? (
 82	        <Popover
 83	          bodyContent={
 84	            <>
 85	              {nodes?.map((node) => {
 86	                const isPreffered = prefferedQualifiedNodesNames?.includes(node.metadata.name);
 87	                return (
 88	                  <Flex key={node.metadata.uid}>
 89	                    <FlexItem spacer={{ default: 'spacerXs' }}>
 90	                      <ResourceLink
 91	                        groupVersionKind={modelToGroupVersionKind(NodeModel)}
 92	                        name={node.metadata.name}
 93	                      />
 94	                    </FlexItem>
 95	                    {isPreffered && (
 96	                      <FlexItem spacer={{ default: 'spacerXs' }}>
 97	                        <GreenCheckCircleIcon /> {t('Preffered')}
 98	                      </FlexItem>
 99	                    )}
100	                  </Flex>
101	                );
102	              })}
103	            </>
104	          }
105	          headerContent={
106	            <>
107	              {t('{{qualifiedNodesCount}} matching Nodes found', {
108	                qualifiedNodesCount: qualifiedNodesSize || prefferedQualifiedNodesSize,
109	              })}
110	            </>
111	          }
112	        >
113	          <Button isInline variant="link">
114	            {t('View matching {{matchingNodeText}}', {
115	              matchingNodeText,
116	            })}
117	          </Button>
118	        </Popover>
119	      ) : (
120	        t('Scheduling will not be possible at this state')
121	      )}
122	    </Alert>
123	  );
124	};
125	
126	export default NodeCheckerAlert;

